```bash
sed -i '/case Instruction::Add:/,/break;/ { /break;/a\  case Instruction::Sub:
    if (match(BO.getOperand(1), m_APInt(C))) {
      bool HasNSW = IIQ.hasNoSignedWrap(&BO);
      bool HasNUW = IIQ.hasNoUnsignedWrap(&BO);
      if (PreferSignedRange && HasNSW && HasNUW)
        HasNUW = false;
      if (HasNUW) {
        // sub nuw x, C produces [0, UINT_MAX - C]
        Upper = APInt::getMaxValue(Width) - *C + 1;
      } else if (HasNSW) {
        if (C->isNegative()) {
          // sub nsw x, -C produces [SINT_MIN + C, SINT_MAX]
          Lower = APInt::getSignedMinValue(Width) + *C;
          Upper = APInt::getSignedMaxValue(Width) + 1;
        } else {
          // sub nsw x, +C produces [SINT_MIN, SINT_MAX - C]
          Lower = APInt::getSignedMinValue(Width);
          Upper = APInt::getSignedMaxValue(Width) - *C + 1;
        }
      }
    } else if (match(BO.getOperand(0), m_APInt(C))) {
      bool HasNSW = IIQ.hasNoSignedWrap(&BO);
      bool HasNUW = IIQ.hasNoUnsignedWrap(&BO);
      if (PreferSignedRange && HasNSW && HasNUW)
        HasNUW = false;
      if (HasNUW) {
        // sub nuw C, x produces [C - UINT_MAX, C] -> [0, C] if C >= 0?
        // Actually, with NUW, C >= x, so result <= C.
        Upper = *C + 1;
      } else if (HasNSW) {
        if (C->isNegative()) {
          // sub nsw -C, x produces [SINT_MIN, -C - SINT_MAX]
          Lower = APInt::getSignedMinValue(Width);
          Upper = *C - APInt::getSignedMaxValue(Width) + 1;
        } else {
          // sub nsw +C, x produces [C - SINT_MAX, SINT_MAX]
          Lower = *C - APInt::getSignedMaxValue(Width);
          Upper = APInt::getSignedMaxValue(Width) + 1;
        }
      }
    }
    break;' llvm/lib/Analysis/ValueTracking.cpp
```

